import{_ as a,C as r,o as i,c as o,E as n,w as s,a as d,a0 as l}from"./chunks/framework.CkNTPv-z.js";const f=JSON.parse('{"title":"Denmark Healthcare & HRT","description":"Transgender healthcare access in Denmark","frontmatter":{"layout":"doc","title":"Denmark Healthcare & HRT","description":"Transgender healthcare access in Denmark"},"headers":[],"relativePath":"europe/denmark/healthcare.md","filePath":"europe/denmark/healthcare.md","lastUpdated":null}'),c={name:"europe/denmark/healthcare.md"};function h(p,e,m,u,g,b){const t=r("Badge");return i(),o("div",null,[n(t,{variant:"green"},{default:s(()=>[...e[0]||(e[0]=[d("Informed Consent",-1)])]),_:1}),e[1]||(e[1]=l('<h1 id="healthcare-hrt-in-denmark" tabindex="-1">Healthcare &amp; HRT in Denmark <a class="header-anchor" href="#healthcare-hrt-in-denmark" aria-label="Permalink to &quot;Healthcare &amp; HRT in Denmark&quot;">​</a></h1><h2 id="access-model" tabindex="-1">Access Model <a class="header-anchor" href="#access-model" aria-label="Permalink to &quot;Access Model&quot;">​</a></h2><p>Denmark operates an informed consent model for transgender healthcare, though with some requirements. Access to HRT is centralised through specialised gender clinics at public hospitals. You typically need a referral from your GP to a gender clinic, where a multidisciplinary team evaluates your needs.</p><p>While informed consent is the framework, wait times for initial appointments at public gender clinics can be 6-12 months. Private options exist with shorter wait times but higher costs.</p><h2 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Services</th></tr></thead><tbody><tr><td>Sexologisk Klinik, Rigshospitalet</td><td>Copenhagen</td><td>National gender clinic, HRT, surgery referrals</td></tr><tr><td>Aalborg University Hospital</td><td>Aalborg</td><td>Gender clinic, HRT, counselling</td></tr><tr><td>Aarhus University Hospital</td><td>Aarhus</td><td>Gender clinic, HRT, psychotherapy</td></tr><tr><td>CKI (Center for Kønsidentitet)</td><td>Odense</td><td>Regional gender services</td></tr></tbody></table><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><p>As an EU member, Denmark recognises prescriptions from other EU/EEA countries. Non-EU arrivals need a Danish doctor&#39;s appointment to convert their prescription. Bring a detailed medical letter in Danish or English listing your medications, dosages, and treatment history.</p><p>A 3-month personal supply of HRT medications is generally permitted at the border with a valid prescription.</p><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><p>Gender-affirming surgeries are performed at Rigshospitalet in Copenhagen and are publicly funded for Danish residents. Top surgery (mammoplasty) and bottom surgery (vaginoplasty, phalloplasty) are available. Hysterectomy and oophorectomy are also covered. Wait times for surgery range from 12-24 months.</p><h2 id="costs" tabindex="-1">Costs <a class="header-anchor" href="#costs" aria-label="Permalink to &quot;Costs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Public Cost</th><th>Private Cost</th></tr></thead><tbody><tr><td>GP visit</td><td>Free (with Yellow Card)</td><td>DKK 300-500</td></tr><tr><td>HRT (monthly)</td><td>DKK 100-300</td><td>DKK 300-600</td></tr><tr><td>Top Surgery</td><td>Free (public)</td><td>DKK 30,000-50,000</td></tr><tr><td>Bottom Surgery</td><td>Free (public)</td><td>DKK 80,000-150,000</td></tr></tbody></table>',13))])}const k=a(c,[["render",h]]);export{f as __pageData,k as default};
